const PersonProfilePage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const person = MOCK_PEOPLE.find((p) => p.id === Number(id));
  if (!person) {
    return <div className="p-10 text-center text-white">Person not found</div>;
  }
  return (
    <div className="min-h-screen flex flex-col gap-6 w-272.5">
      <h1 className="text-3xl font-semibold text-white">User Profile</h1>
      {/* Profile*/}
      <div className="w-272.5 h-57.25 bg-black border border-[#364153] rounded-xl flex justify-between p-6">
        <div className="flex gap-3">
          <img
            src={person.avatar}
            className="w-40.75 h-46.25 rounded-md object-cover"
          />
          <div className="flex flex-col text-white">
            <span className="font-semibold">{person.name}</span>
            <span className="text-slate-400 text-sm">{person.role}</span>
          </div>
        </div>
        <Button className="w-27 h-8 text-sm rounded-md px-3 py-0">
          Share Profile
        </Button>
      </div>

      <h2 className="text-2xl font-bold text-white">Portfolio</h2>
      {/* Projects Grid */}
      <div className="grid grid-cols-3 gap-8.75 w-270.25">
        {person.projectDetails.map((project, index) => (
          <div
            key={index}
            className="bg-black border border-[#364153] rounded-xl p-7 flex flex-col items-center gap-3.5 text-white"
          >
            <img
              src={project.avatar}
              className="w-70.25 h-38 rounded-xl border border-[#818181] object-cover"
            />
            <div className="flex flex-col items-center gap-3 w-full">
              <h3 className="font-semibold text-xl text-center">
                {project.name}
              </h3>
              <p className="text-sm text-[#99A1AF] font-light text-center max-h-[80px] overflow-y-auto">
                {project.details}
              </p>
            </div>
            <div className="flex gap-4 text-slate-400 text-sm mt-auto">
              <div className="flex items-center gap-1">
                <Heart className="w-4 h-4" />
                {project.count}
              </div>
              <div className="flex items-center gap-1">
                <Eye className="w-4 h-4" />
                {project.see}
              </div>
            </div>
          </div>
        ))}
      </div>
      {/* Back Button optional*/}
      <div className="mt-auto pt-6">
        <Button
          variant="secondary"
          onClick={() => navigate(-1)}
          className="flex items-center gap-2"
        >
          <ArrowLeft className="w-4 h-4" />
          Back
        </Button>
      </div>
    </div>
  );
};
export default PersonProfilePage;
